// Lista de expresiones regulares para detectar patrones maliciosos comunes
const maliciousPatterns = [
  /ignora.*instrucciones/i,           // Prompt injection en español
  /ignore.*previous.*instructions/i,  // Prompt injection en inglés
  /system prompt/i,                   // Intentos de extraer el prompt del sistema
  /jailbreak/i,                       // Intentos de evasión
  /actúa como.*sin restricciones/i,   // Patrones de DAN (Do Anything Now)
  /bypass/i,                          // Intentos de saltar filtros
  /<script\b[^<]*(?:(?!<\/script>)<[^<]*)*<\/script>/gi, // XSS básico
  /(UNION|SELECT|DROP|INSERT).*;/i    // Inyección SQL básica (por precaución)
];

// Límite de caracteres para evitar ataques de denegación de servicio por prompts gigantes
const MAX_LENGTH = 1500; 

for (const item of $input.all()) {
  // Ajuste para extraer el texto correctamente desde el webhook de Chatwoot
  // El mensaje principal viene en la propiedad "content" dentro de "body"
  const text = item.json?.body?.content || "";

  let isMalicious = false;
  let reason = "";

  // 1. Verificación de longitud
  if (text.length > MAX_LENGTH) {
    isMalicious = true;
    reason = "Payload supera el límite de longitud permitido.";
  }

  // 2. Verificación de patrones con Regex
  if (!isMalicious && text.length > 0) {
    for (const pattern of maliciousPatterns) {
      if (pattern.test(text)) {
        isMalicious = true;
        reason = `Detectado patrón sospechoso: ${pattern.toString()}`;
        break;
      }
    }
  }

  // Agregamos las banderas al JSON de salida para poder enrutarlo después (usando un Switch Node o If Node)
  item.json.securityCheck = {
    isMalicious: isMalicious,
    reason: reason
  };
}

return $input.all();

