// 1. Obtenemos el texto crudo que devolvió el Agente
let rawOutput = $input.first().json.output || "";

// 2. Limpiamos cualquier rastro de Markdown que el LLM haya podido agregar por error
let cleanedOutput = rawOutput.replace(/```json/g, '').replace(/```/g, '').trim();

try {
  // 3. Convertimos el texto en un objeto JSON procesable
  const parsedData = JSON.parse(cleanedOutput);

  // 4. (NUEVO) Aseguramos que la estructura de datos_cita esté completa.
  // Si la IA olvidó el campo del correo, lo forzamos a null para evitar errores en los siguientes nodos.
  if (parsedData.datos_cita) {
      parsedData.datos_cita.correo_electronico = parsedData.datos_cita.correo_electronico || null;
  }

  // Retornamos los datos limpios para que los siguientes nodos los usen
  return { json: parsedData };

} catch (error) {
  // 5. Mecanismo de seguridad: Si el LLM alucinó y no dio un JSON válido, 
  // enviamos un mensaje de error al paciente y evitamos que el flujo falle críticamente.
  return {
    json: {
      "mensaje_paciente": "Tuvimos un pequeño inconveniente procesando tu solicitud en el sistema. ¿Podrías confirmarme tu requerimiento nuevamente?",
      "accion_realizada": "NONE",
      "datos_cita": {
        "nombre_paciente": null,
        "correo_electronico": null,
        "fecha_hora": null,
        "motivo_consulta": null,
        "google_event_id": null
      },
      "error_interno": error.message
    }
  };
}
